using System;
using System.Collections.Generic;
using System.IO;
using System.Xml;

public class XmlConfigParser
{
    public static Dictionary<string, string> ParseXmlConfiguration(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        using (var reader = XmlReader.Create(xmlFilePath, new XmlReaderSettings { DtdProcessing = DtdProcessing.Parse }))
        {
            while (reader.Read())
            {
                if (reader.IsStartElement())
                {
                    switch (reader.Name)
                    {
                        case "setting":
                            var key = reader.GetAttribute("name");
                            var value = reader.ReadElementContentAsString();
                            settings[key] = value;
                            break;
                    }
                }
            }
        }
        return settings;
    }
}